def test_request_id_header_is_preserved() -> None:
    """When the client supplies X-Request-ID the same value should appear on the response."""
    import os  # noqa: PLC0415
    import urllib.request  # noqa: PLC0415
    base = os.environ.get("SUT_URL", "http://127.0.0.1:8000")
    url = f"{base}/fixtures/request_id_header_is_preserved/request-id/preserved"
    _headers = {
        "X-Request-ID": "trace-123",
    }
    _req = urllib.request.Request(url, headers=_headers, method="GET")
    class _NoRedirect(urllib.request.HTTPRedirectHandler):  # noqa: N801
        def redirect_request(self, *args, **kwargs):
            return None
    _opener = urllib.request.build_opener(_NoRedirect())
